INSERT INTO place_translations (place_id, lang, name, description, location, category, duration, price, best_time, tags)
SELECT v.place_id, v.lang::varchar(5), v.name, v.description, v.location, v.category, v.duration, v.price, v.best_time, NULL::jsonb
FROM (
VALUES
('tripoli_introduction','ar','طرابلس — مقدمة','تُعد طرابلس ثاني أكبر مدينة في لبنان وعاصمة الشمال، وتقع على بُعد 85 كيلومترًا شمال بيروت. إنها مدينة ودودة تتعايش فيها الحداثة مع التاريخ، ويجتمع فيها الاقتصاد المزدهر مع نمط الحياة الهادئ. تضم طرابلس العديد من المباني التاريخية والأثرية: المساجد، والمدارس، والخانات، والحمامات العامة، ومعظمها يعود إلى الحقبة المملوكية، وتحديدًا القرن الرابع عشر الميلادي. وتُشكّل الأسواق والخانات، التي تجمع الحرفيين من أصحاب المهن الواحدة — كصانعي الصابون، والصياغ، والعطّارين، والدبّاغين، والخياطين وغيرهم — أحياءً عمرانية متميزة لا تزال تحتفظ بالكثير من ملامح العصور الوسطى.','طرابلس، شمال لبنان','مقدمة طرابلس والتاريخ','قراءة 15–30 دقيقة','','في أي وقت'),
('tripoli_introduction','fr','Tripoli — introduction','Tripoli est la deuxième ville du Liban et la capitale du Nord, située à 85 kilomètres au nord de Beyrouth. C''est une ville accueillante où modernité et histoire coexistent. Tripoli abrite de nombreux bâtiments historiques : mosquées, écoles, khans et bains publics, dont la plupart datent de l''époque mamelouke, surtout du XIVe siècle. Les souks et khans regroupent les artisans d''un même métier — savonniers, orfèvres, parfumeurs, tanneurs, tailleurs — formant des quartiers qui conservent encore un fort caractère médiéval.','Tripoli, Liban-Nord','Tripoli — introduction et histoire','Lecture 15–30 min','','À tout moment'),
('tripoli_journey_history','ar','رحلة في عمق التاريخ','على الرغم من قلة الاكتشافات الأثرية، فإن السجلات التاريخية تؤكد وجود طرابلس منذ القرن الرابع عشر قبل الميلاد. أنشأ الفينيقيون مركزًا تجاريًا على طرف شبه الجزيرة التي تحتضن اليوم مدينة الميناء؛ وفي الحقبة الفارسية تطوّر هذا المركز ليُصبح مركزًا فدراليًا. تمتعت طرابلس بموقع استراتيجي: بوابة الجنوب إلى سهل عكار، ميناءان طبيعيان، وجزر صغيرة تقيها من البحر. في العصر الهلنستي ظلّت محطة بحرية مهمة؛ مع الرومان بلغت المدينة ذروة مجدها بمبانٍ عامة ضخمة؛ وفي عام 551 ميلادية ضربها زلزال مدمر وتسونامي. بعد الفتح الإسلامي (بعد 635 م) أصبحت محطة للأسطول الأموي؛ في منتصف القرن الحادي عشر نالت درجة من الحكم الذاتي في عهد بني عمار الفاطمي وبرزت كمركز للعلم والثقافة؛ وفي 1109 تعرّضت لانتكاسة مع الحصار الصليبي. بعد الفتح الإسلامي أصبحت أيضًا مركزًا بحريًا وثقافيًا بارزًا في المنطقة.','نظرة تاريخية — طرابلس','مقدمة طرابلس والتاريخ','قراءة 30–45 دقيقة','','في أي وقت'),
('tripoli_journey_history','fr','Un voyage dans l’histoire','Les sources confirment Tripoli dès le XIVe siècle av. J.-C. Les Phéniciens y fondèrent un comptoir sur la péninsule de El-Mina; à l''époque perse, il devint un pôle fédéral. La ville contrôlait routes commerciales et militaires entre mer et Homs. Sous les successeurs d''Alexandre elle resta une base navale; sous Rome elle connut son apogée (temples, stade). En 551 un tremblement de terre et un tsunami mirent fin à une longue prospérité byzantine. Après 635 elle servit la flotte omeyyade; au XIe siècle, sous les juges Banu Ammar fatimides, elle gagna en autonomie culturelle; en 1109 les Croisés prirent la ville. Elle demeura un centre maritime et culturel majeur.','Synthèse historique — Tripoli','Tripoli — introduction et histoire','Lecture 30–45 min','','À tout moment'),
('tripoli_citadel_saint_gilles','ar','قلعة طرابلس (سان جيل)','تقع قلعة طرابلس على تلة أبي سمراء، المعروفة في الحقبة الصليبية باسم «تلة الحجاج». أُسِّست عام 645م على يد القائد العربي سفيان الأزدي، ثم أعاد الكونت ريمون دو سان جيل بناءها؛ أحرقها المماليك عام 1289م ثم أعاد الأمير أسندمر الكرجي تشييدها. يضمّ الحصن بابًا رئيسيًا في البرج الأول وبابين صغيرين؛ وفي الداخل مسارات إلى مستويات سُفلية استُخدمت كسجون ومخابئ أسلحة وسراديب تتصل بمنازل وأبراج ساحلية.','تلة أبي سمراء، طرابلس','القلاع والأبراج','1–2 ساعة','','صباحًا أو قبل الغروب'),
('tripoli_citadel_saint_gilles','fr','Citadelle de Tripoli (Saint-Gilles)','Sur la colline d''Abou Samra (« Tallat Al-Houjaj » à l''époque des croisés). Fondée en 645 par Soufyan al-Azadi, reconstruite par Raymond de Saint-Gilles, brûlée par les Mamelouks en 1289 puis relevée par l''émir Asandamir al-Korji. Grande porte dans la première tour, deux petites portes; escaliers vers des niveaux inférieurs (prisons, armureries, catacombes liées aux maisons et tours côtières).','Colline Abou Samra, Tripoli','Citadelles et tours','1–2 h','','Matin ou fin d’après-midi'),
('barsbay_tower','ar','برج السباع (برسباي)','شُيّد في منتصف القرن الرابع عشر على يد الأمير سيف الدين برسباي بن عبد الله بن حمزة الناصري. يُعدّ نموذجًا بارزًا لفن العمارة العسكرية المملوكية.','منطقة الميناء / الساحل، طرابلس','القلاع والأبراج','30–45 دقيقة','','نهارًا'),
('barsbay_tower','fr','Tour de Barsbay (tour du Lion)','Construite au milieu du XIVe siècle par l''émir Saif al-Din Barsabay ibn Abdullah al-Nasiri. Exemple remarquable de l''architecture militaire mamelouke.','Front de mer / port, Tripoli','Citadelles et tours','30–45 min','','En journée'),
('great_mansouri_mosque','ar','الجامع المنصوري الكبير','أقدم مساجد المدينة وأول مسجد يُشيّد في عهد المماليك. أُقيم عام 1294م على يد السلطان الأشرف خليل بن قلاوون فوق أنقاض كنيسة؛ وأضاف السلطان الناصر محمد بن قلاوون عام 1315م الأروقة الخارجية. المساحة نحو 3,224 م²؛ المئذنة أربع طبقات على الطراز اللومباردي الإيطالي وقد كانت برج جرس أُعيد استخدامه. المنبر الخشبي مزدان بزخارف هندسية دقيقة.','حي النوري — المدينة القديمة','المساجد والجوامع','45 دقيقة – ساعة','','بين أوقات الصلاة'),
('great_mansouri_mosque','fr','Grande mosquée al-Mansouri','Plus ancienne mosquée de Tripoli et première des Mamelouks. Édifiée en 1294 par le sultan Ashraf Khalil ibn Qalawun sur une église; arcades de la cour ajoutées en 1315 par al-Nasser Muhammad. Environ 3 224 m²; minaret à quatre niveaux de style lombard (clocher réutilisé). Minbar en bois à motifs géométriques.','Quartier al-Nouri, vieille ville','Mosquées historiques','45 min – 1 h','','Entre les prières'),
('sidi_abd_al_wahed_meknasi_mosque','ar','جامع سيدي عبد الواحد المكناسي','أُنجز بناؤه عام 1306م على يد الشيخ عبد الواحد المكناسي من المغرب. من أقدم المساجد المملوكية؛ يتميّز بتأثير معماري مغربي ومئذنة صغيرة نسبيًا.','المدينة القديمة','المساجد والجوامع','20–30 دقيقة','','بين أوقات الصلاة'),
('sidi_abd_al_wahed_meknasi_mosque','fr','Mosquée Sidi Abd al-Wahed al-Meknasi','Construite en 1306 par le cheikh Abd Al-Wahed al-Meknasi, saint venu du Maroc. Parmi les plus anciennes mosquées mameloukes; style marocain et minaret modeste.','Vieille ville','Mosquées historiques','20–30 min','','Entre les prières'),
('al_burtasi_mosque_madrasa','ar','جامع ومدرسة البرطاسي','في القرن الرابع عشر شيّد عيسى بن عمر البرطاسي جامعًا ومدرسة فقهية شافعية على ضفاف نهر أبو علي. لفت أنظار الرحّالة الأوروبيين في القرن التاسع عشر. مئذنة على قوس وتأثيرات بيزنطية وفاطمية وأندلسية.','ضفة نهر أبو علي','المساجد والجوامع','30–45 دقيقة','','نهارًا'),
('al_burtasi_mosque_madrasa','fr','Mosquée et madrasa al-Burtasi','Au XIVe siècle, Issa ibn Omar al-Burtasi bâtit mosquée et école chaféite sur l''Abou Ali. Admirée des voyageurs européens au XIXe siècle. Minaret en arc; influences byzantine, fatimide et andalouse.','Rive de l’Abou Ali','Mosquées historiques','30–45 min','','En journée'),
('al_tawba_mosque','ar','جامع التوبة','في عهد السلطان الناصر قلاوون، القرن الرابع عشر. ارتبط برواية عن مهندس الجامع المنصوري وبناء هذا الجامع توبةً. على ضفاف أبو علي؛ لوحة برونزية توثق فيضان 1643م؛ مئذنة سداسية وقباب جميلة.','ضفة نهر أبو علي','المساجد والجوامع','30 دقيقة','','بين أوقات الصلاة'),
('al_tawba_mosque','fr','Mosquée al-Tawba','Sous al-Nasser Qalawun, XIVe siècle. Légende de l''architecte de la Grande Mosquée et expiation. Sur l''Abou Ali; plaque de bronze de l''inondation de 1643; minaret hexagonal et dômes élégants.','Rive de l’Abou Ali','Mosquées historiques','30 min','','Entre les prières'),
('al_attar_mosque','ar','جامع العطار','بُني عام 1334م على يد بدر الدين العطار فوق أنقاض كنيسة صليبية؛ شمال خان المصريين. مئذنة مربعة شاهقة تشبه البرج الحربي؛ ثلاثة أبواب بزخارف ونقوش.','المدينة القديمة','المساجد والجوامع','30–45 دقيقة','','بين أوقات الصلاة'),
('al_attar_mosque','fr','Mosquée al-Attar','1334 par Badr al-Din al-Attar sur une église croisée; au nord du khan al-Masriyine. Minaret carré, très haut, de type tour militaire; trois portes ornées.','Vieille ville','Mosquées historiques','30–45 min','','Entre les prières'),
('taynal_mosque','ar','جامع طينال','خارج أسوار المدينة في باب الرمل؛ بأمر الأمير سيف الدين طينال الحاجب. هندسة دفاعية؛ ممرات سرية في الجدران؛ باحة رخام وقبة على أعمدة غرانيت؛ مئذنة بسلالم حجرية مزدوجة؛ محراب خشبي مميز.','باب الرمل','المساجد والجوامع','45 دقيقة – ساعة','','صباحًا'),
('taynal_mosque','fr','Mosquée Taynal','Hors les murs, Bab al-Raml, par l''émir Saif al-Din Taynal. Architecture défensive, passages secrets, cour en marbre, coupole sur colonnes de granit, minaret à doubles escaliers, beau mihrab en bois.','Bab al-Raml','Mosquées historiques','45 min – 1 h','','Matin'),
('al_uwaysiya_mosque','ar','جامع الأويسية','على الضفة الغربية لأبو علي؛ أصله زاوية مملوكية حوّلها العثمانيون إلى مسجد وأضافوا مئذنة عثمانية. تُعد قبته من أكبر قباب المساجد التاريخية في المدينة.','طلعة سوق السمك','المساجد والجوامع','30 دقيقة','','بين أوقات الصلاة'),
('al_uwaysiya_mosque','fr','Mosquée al-Uwaysiyat','Rive ouest de l''Abou Ali. Petite zawiya mamelouke convertie en mosquée par les Ottomans avec minaret ottoman. Grand dôme parmi les mosquées historiques.','Vers le marché au poisson','Mosquées historiques','30 min','','Entre les prières'),
('al_tahham_mosque','ar','جامع الطحّام','في حي الحدادين فوق الحوانيت، يُصعد إليه بدرج. عهد مملوكي؛ الباني مجهول. مئذنة قصيرة بزخارف دقيقة؛ أعمدة غرانيت بتيجان كورنثية.','الحدادين','المساجد والجوامع','20–30 دقيقة','','بين أوقات الصلاة'),
('al_tahham_mosque','fr','Mosquée al-Tahham','Quartier Haddadine, au-dessus des boutiques, escalier d''accès. Époque mamelouke, bâtisseur inconnu. Minaret court mais riche décor; colonnes de granit à chapiteaux corinthiens.','Haddadine','Mosquées historiques','20–30 min','','Entre les prières'),
('al_muallaq_mosque','ar','جامع المعلّق','في الحدادين فوق قبوة ومخازن؛ بناه محمود لطفي الزعيم 1555م. يُعرف بالمحمودية. مئذنة ثمانية الأضلاع بأقواس وشرفات مزخرفة.','الحدادين','المساجد والجوامع','30–45 دقيقة','','بين أوقات الصلاة'),
('al_muallaq_mosque','fr','Mosquée al-Muallaq (suspendue)','1555 par Mahmoud Lotfi al-Zaim, sur caves et magasins. Minaret octogonal à huit arêtes, arches et petits balcons fleuris. Aussi dite al-Mahmoudiya.','Haddadine','Mosquées historiques','30–45 min','','Entre les prières'),
('al_hamdi_mosque','ar','جامع الحميدي','سُمّي سابقًا جامع التفاحي أو جامع الدباغين؛ يُرجّح مطلع القرن السادس عشر. هُدم وأُعيد بناؤه 1892 في عهد عبد الحميد الثاني.','المدينة القديمة','المساجد والجوامع','20–30 دقيقة','','بين أوقات الصلاة'),
('al_hamdi_mosque','fr','Mosquée al-Hamdi','Anciennement mosquée Tuffahi / des tanneurs; début XVIe siècle mamelouk. Détruite et reconstruite en 1892 sous Abdul Hamid II.','Vieille ville','Mosquées historiques','20–30 min','','Entre les prières'),
('al_mashhad_madrasa','ar','المشهد (مدرسة)','في حي النوري مقابل المدرسة الشمسية؛ سُميت لضريح داخلها. بوابة بفسيفساء ورخام أبيض وأخضر ومقرنصات مملوكية.','حي النوري','المدارس','30–45 دقيقة','','صباحًا'),
('al_mashhad_madrasa','fr','Madrasa al-Mashhad','Quartier al-Nouri, face à l''école solaire; nom lié au mausolée. Portail à mosaïques, marbre blanc et vert, muqarnas mamelouks.','Al-Nouri','Madrasas','30–45 min','','Matin'),
('al_nouriya_madrasa','ar','المدرسة النورية','اختلاف حول الباني: سنقر النوري ~1310 أو نور الدين وأثرياء المدينة؛ حمّام النوري مقابلها. مدخل بحجارة بيضاء وسوداء؛ محراب رخامي بفسيفساء من أجمل المحاريب في طرابلس.','حي النوري','المدارس','30–45 دقيقة','','صباحًا'),
('al_nouriya_madrasa','fr','Madrasa al-Nouriya','Attribution incertaine (Sanqar al-Nouri ~1310 ou Nour al-Din); hammam al-Nouri en face. Portail pierres noires et blanches; beau mihrab en marbre mosaïqué.','Al-Nouri','Madrasas','30–45 min','','Matin'),
('al_qartawiya_madrasa','ar','المدرسة القرطاوية','من أكبر مدارس المماليك؛ ضمن حلقة حول الجامع المنصوري. أمر ببنائها قرطاي 1316–1326. الجدار الخلفي بآيات وزخارف لنشر المراسيم؛ بوابة ضخمة بمقرنصات.','جوار الجامع المنصوري','المدارس','30–45 دقيقة','','صباحًا'),
('al_qartawiya_madrasa','fr','Madrasa al-Qartawiyat','Grande école mamelouke autour de la Grande Mosquée, commandée par Qurtay (1316-1326). Mur arrière avec versets pour affichage des décrets; portail monumental à muqarnas.','Près de la Grande Mosquée','Madrasas','30–45 min','','Matin'),
('al_qadiriya_madrasa','ar','المدرسة القادرية','من أكبر المدارس بعد القرطاوية؛ القرن الرابع عشر. حُوّلت مؤخرًا إلى مسجد. بوابة بلا زخارف؛ ضريح مجهول الهوية.','المدينة القديمة','المدارس','30–45 دقيقة','','صباحًا'),
('al_qadiriya_madrasa','fr','Madrasa al-Qadiriya','Grande école après Qartawiyat, XIVe siècle; récemment convertie en mosquée. Portail sobre; mausolée au saint inconnu.','Vieille ville','Madrasas','30–45 min','','Matin'),
('al_nasiriya_madrasa','ar','المدرسة الناصرية','منتصف القرن الرابع عشر؛ السلطان حسن بن محمد بن قلاوون (الناصر). إلى يسار الطريق للجامع المنصوري؛ نقش «عزّ لمولانا السلطان ناصر».','جوار الجامع المنصوري','المدارس','30–45 دقيقة','','صباحًا'),
('al_nasiriya_madrasa','fr','Madrasa al-Nasiriya','Milieu du XIVe siècle par le sultan Hassan al-Nasir. À gauche vers la Grande Mosquée; inscription « Gloire à notre sultan Nasir ».','Près de la Grande Mosquée','Madrasas','30–45 min','','Matin'),
('al_saqraqiya_madrasa','ar','المدرسة السقرقية','أنشأها سيف الدين أقرق في النصف الأول من القرن الرابع عشر. واجهة بنقوش توثق التأسيس والأوقاف.','المدينة القديمة','المدارس','30–45 دقيقة','','صباحًا'),
('al_saqraqiya_madrasa','fr','Madrasa al-Saqraqiyat','Première moitié du XIVe siècle par Saif al-Din Aqraq. Façade avec inscriptions sur la fondation et les biens fondés.','Vieille ville','Madrasas','30–45 min','','Matin'),
('al_khatouniya_madrasa','ar','المدرسة الخاتونية','1374م؛ الأمير عز الدين إيدمر الأشرفي وزوجته أرغون خاتون. في الحدادين مقابل السقرقية؛ نقش الوقف وشعار الأمير.','صف البلاط، الحدادين','المدارس','30–45 دقيقة','','صباحًا'),
('al_khatouniya_madrasa','fr','Madrasa al-Khatouniya','1374 par Izz Ed-Dine Idmer al-Ashrafi et Arghun Khatoun. Haddadine, face à Saqraqiya; inscription de waqf et armoiries.','Haddadine','Madrasas','30–45 min','','Matin'),
('al_khanqah_tripoli','ar','الخانقاه','1467م في الحدادين؛ عهد قايناي المؤيدي. نُسبت للست صالحة. آوى متصوفين ومحاربين وزوارًا. بوابة كبيرة، ممر ضيق، فناء ببركة.','الحدادين','التكايا والخانقاه','30 دقيقة','','حسب التنسيق'),
('al_khanqah_tripoli','fr','Khanqah','1467 à Haddadine sous Qaynay al-Mu''ayyadi; liée à Sitt Salha. Accueillait soufis, guerriers et hôtes. Grande porte, couloir, cour avec bassin.','Haddadine','Khanqahs et takiyas','30 min','','Sur rendez-vous'),
('takiya_al_mawlawiya','ar','التكية المولوية','1619م؛ صامصونجي علي. من تكايا المولوية خارج تركيا (القاهرة، القدس، دمشق، حلب، البوسنة، قبرص). مركز للطريقة الرومية حتى منتصف القرن العشرين.','طرابلس','التكايا والخانقاه','30–45 دقيقة','','حسب الزيارة'),
('takiya_al_mawlawiya','fr','Takiya al-Mawlawiya','1619 par Samsunji Ali. Takiya mawlawiya ottomane (Caire, Jérusalem, Damas, Alep, Bosnie, Chypre). Centre de l''ordre de Jalaluddin Rumi jusqu''au milieu du XXe siècle.','Tripoli','Khanqahs et takiyas','30–45 min','','Selon accès'),
('souk_haraj','ar','سوق الحراج','مبنى صليبي بقاعة وأقبية متقاطعة وعمودان ضخمان؛ ربما بقايا كنيسة أو معبد روماني. في العصر المملوكي حُوّل إلى خان بطابق للتجار وطابق للتجارة والحيوانات.','الأسواق القديمة','الخانات','30–45 دقيقة','','صباحًا'),
('souk_haraj','fr','Souk al-Haraj','Monument croisé à voûtes croisées et deux colonnes; réemploi possible d''église ou temple romain. Sous les Mamelouks, khan avec étage marchands et rez commercial.','Vieux souks','Khans','30–45 min','','Matin'),
('khan_al_askar','ar','خان العسكر','بديل عن تحويل القلعة الصليبية إلى ثكنة بعد الحريق؛ كتلتان مستطيلتان وإسطبل وسطي؛ نحو 400 م²؛ استُخدم في العثماني والفرنسي.','المدينة القديمة','الخانات','45 دقيقة – ساعة','','صباحًا'),
('khan_al_askar','fr','Khan al-Askar','Après l''incendie de la citadelle croisée, caserne mamelouke sur ~400 m²; usage ottoman et français.','Vieille ville','Khans','45 min – 1 h','','Matin'),
('khan_al_khayyatin','ar','خان الخياطين','مستطيل طويل؛ الطابق الأرضي كممرّ حرفيين؛ العلوي بعقود؛ مدخلان شرقي وغربي؛ المدخل الغربي بعمود وتاج كورنثي روماني. يُؤرّخ غالبًا لـ1650م.','أسواق المدينة القديمة','الخانات','ساعة','','صباحًا حتى الظهر'),
('khan_al_khayyatin','fr','Khan al-Khayyatin','Plan allongé, rez comme rue d''ateliers, étage sous dix arches, deux entrées; colonne corinthienne à l''ouest. Souvent daté vers 1650.','Vieux souks','Khans','1 h','','Matin'),
('khan_al_saboun','ar','خان الصابون','1480م؛ يوسف بك سيفا؛ ثكنة ثم خان؛ شهير بالصابون؛ البوابة الخشبية العالية الأصلية بفتحات للحراس.','المدينة القديمة','الخانات','45 دقيقة – ساعة','','نهارًا'),
('khan_al_saboun','fr','Khan al-Saboun','1480 par Yusuf Bey Sifa; caserne puis khan; célèbre pour le savon; haute porte en bois d''origine avec fenêtres de garde.','Vieille ville','Khans','45 min – 1 h','','Journée'),
('hammam_izz_ed_dine','ar','حمام عز الدين','من أقدم الحمامات؛ بجوار خان الخياطين؛ 1294م عز الدين أيبك الموصلي على بقايا صليبية؛ رخام كارارا؛ مدخل من سوق النحاسين؛ نقش صليبي و«حمل الفصح».','جوار خان الخياطين','الحمامات','45 دقيقة','','ساعات التشغيل'),
('hammam_izz_ed_dine','fr','Hammam Izz Ed-Dine','Près du Khan al-Khayyatin; 1294 par Izz Ed-Dine Aybak sur ruines croisées; marbre Carrare; entrée côté souk du cuivre; inscription et Agneau pascal.','Près du Khan al-Khayyatin','Hammams','45 min','','Horaires'),
('hammam_al_nouri','ar','حمام النوري','في محلة النوري بمحاذاة الجامع المنصوري والمدارس. جدل في الباني؛ النصف الأول من القرن الثامن الهجري مع المدرسة النورية المقابلة.','حي النوري','الحمامات','45 دقيقة','','حسب الفتح'),
('hammam_al_nouri','fr','Hammam al-Nouri','Quartier al-Nouri près de la Grande Mosquée. Attribution incertaine; première moitié du VIIIe H. en parallèle de la madrasa Nouriya.','Al-Nouri','Hammams','45 min','','Selon ouverture'),
('hammam_al_abed','ar','حمام العبد','الحمام التقليدي الوحيد العامل؛ منتصف القرن السابع عشر عثماني؛ التسمية مرتبطة بخادم قُتل عند الباب. قبة وبركة ووسطاني وجواني بخار.','المدينة القديمة','الحمامات','1–2 ساعة','','بعد الظهر أو مساءً'),
('hammam_al_abed','fr','Hammam al-Abed','Seul hammam historique encore en service; milieu XVIIe siècle ottoman; nom lié à un serviteur tué à l''entrée. Dôme, bassin, parties tiède et chaude.','Vieille ville','Hammams','1–2 h','','Après-midi / soir'),
('hammam_al_jadid','ar','حمام الجديد','1740م أسعد باشا العظم؛ بوابة فخمة؛ قاعة وقبة ورخام ونافورة؛ أسطورة سلسلة 14 حلقة من حجر واحد ودلو.','المدينة القديمة','الحمامات','ساعة','','حسب التنسيق'),
('hammam_al_jadid','fr','Hammam al-Jadid','1740 par Asaad Pacha al-Azem; portail somptueux, grande salle, dôme, marbre, fontaine; légende des 14 anneaux sculptés dans une seule pierre.','Vieille ville','Hammams','1 h','','Sur rendez-vous'),
('tripoli_old_markets_network','ar','أسواق طرابلس القديمة','من أندر الأسواق العالمية التي تحافظ على وظيفتها منذ أكثر من ثمانية قرون؛ شبكة من الضفة الشرقية لأبو علي إلى بوابة الحدادين؛ أسواق حسب الحرف: كندرجية، صاغة، عطارين وغيرها.','من النهر إلى الحدادين','أسواق طرابلس القديمة','2–3 ساعات','','صباحًا'),
('tripoli_old_markets_network','fr','Anciens souks de Tripoli','Réseau de souks actifs depuis plus de huit siècles, de la rive est de l''Abou Ali à la porte Haddadine; souks spécialisés (souliers, or, épices…).','Rivière → Haddadine','Anciens souks de Tripoli','2–3 h','','Matin'),
('shrine_our_lady_yunis','ar','مزار سيّدة يونس','في قلب المدينة القديمة؛ نقوش لاتينية تشير للعهد الصليبي؛ رواية نجاة آل يونس بظهور العذراء.','المدينة القديمة','الكنائس والمزارات','20–30 دقيقة','','نهارًا'),
('shrine_our_lady_yunis','fr','Sanctuaire Notre-Dame de Yunis','Cœur de la vieille ville; inscriptions latines croisées; légende du membre de la famille Yunis sauvé par la Vierge.','Vieille ville','Églises et sanctuaires','20–30 min','','Journée'),
('st_george_greek_orthodox_cathedral','ar','كاتدرائية مار جاورجيوس (الروم الأرثوذكس)','1863م؛ عشر سنوات بناء؛ لوحة باسم صوفرينيوس؛ أيقونات وزخارف غنية؛ الدبّاغة قرب شارع الكنائس.','الدبّاغة','الكنائس والمزارات','30–45 دقيقة','','حسب القداس'),
('st_george_greek_orthodox_cathedral','fr','Cathédrale Saint-Georges (grecque orthodoxe)','Début des travaux en 1863, dix ans; plaque Sophrianos; riche en icônes. Quartier Dabbaghah, rue des Églises.','Dabbaghah','Églises et sanctuaires','30–45 min','','Selon offices'),
('st_nicholas_greek_orthodox_church','ar','كنيسة مار نقولا (الروم الأرثوذكس)','اتفاق أوائل القرن التاسع عشر لإزالة الكنيسة القديمة بجوار جامع العويسية وبناء بديل في التربيعة؛ طراز مشرقي مستطيل بلا قباب؛ متحف أيقونات.','التربيعة','الكنائس والمزارات','30 دقيقة','','حسب الزيارة'),
('st_nicholas_greek_orthodox_church','fr','Église Saint-Nicolas (grecque orthodoxe)','Début XIXe: démolition de l''église près de la mosquée al-Uwaysiyat; nouvelle église à Tarbia; style levantin rectangulaire; musée d''icônes.','Tarbia','Églises et sanctuaires','30 min','','Sur rendez-vous'),
('st_joseph_syriac_catholic_church','ar','كنيسة مار يوسف (السريان الكاثوليك)','القرن التاسع عشر؛ مواجهة لكاتدرائية مار جاورجيوس؛ بدأت فرنسيسكانية ثم سريانية كاثوليكية.','جوار الكاتدرائية الأرثوذكسية','الكنائس والمزارات','20 دقيقة','','حسب الزيارة'),
('st_joseph_syriac_catholic_church','fr','Église Saint-Joseph (syriaque catholique)','XIXe siècle en face de Saint-Georges; d''abord franciscaine, puis syriaque catholique.','Près de Saint-Georges','Églises et sanctuaires','20 min','','Sur rendez-vous'),
('st_michael_maronite_church','ar','كنيسة مار ميخائيل (الموارنة)','كاتدرائية مارونية كبرى؛ نمط غربي؛ لوحة فوق المدخل تشير إلى 1858م.','طرابلس','الكنائس والمزارات','30 دقيقة','','حسب الزيارة'),
('st_michael_maronite_church','fr','Église Saint-Michel (maronite)','Grande cathédrale maronite, style occidental; plaque de 1858 au-dessus du portail.','Tripoli','Églises et sanctuaires','30 min','','Sur rendez-vous'),
('el_mina_train_station','ar','محطّة القطار','مطلع القرن العشرين؛ أول قطار إلى الميناء؛ محطة على خط الشرق السريع؛ تمويل من العائلات الطرابلسية؛ ربط بإسطنبول وأوروبا. اليوم كمتحف مفتوح؛ قطارات ألمانية 1895 وفرنسية 1901 بحسب الجرد المحلي.','الميناء','معالم حديثة','30–45 دقيقة','','نهارًا'),
('el_mina_train_station','fr','Gare (El-Mina)','Début XXe siècle; première arrivée du train; station sur l''Orient-Express financée par les familles; liaison Istanbul et Europe. Aujourd''hui musée à ciel ouvert; trains allemands 1895 et français 1901.','El-Mina','Patrimoine moderne','30–45 min','','Journée'),
('al_hamidiya_clock','ar','ساعة الحميدية (التل)','1903م بحسب النص العربي المقدّم (أو 1901 في مصادر أخرى)؛ الذكرى الـ25 لتولي عبد الحميد الثاني؛ مقابل السرايا 1890؛ هُدمت السرايا في الستينيات؛ خمس طبقات وسلم حلزوني حديدي.','ساحة التل','معالم حديثة','15–20 دقيقة','','أي وقت'),
('al_hamidiya_clock','fr','Horloge al-Hamidiya (Al-Tal)','Construite en 1903 (sources varient) pour le 25e anniversaire d''Abdul Hamid II; face à la Saraya (1890, démolie dans les années 1960). Cinq niveaux, escalier en fer.','Place Al-Tal','Patrimoine moderne','15–20 min','','À tout moment'),
('al_tal_square','ar','ساحة التل','أواخر القرن التاسع عشر؛ مركز المدينة الحديثة خارج المدينة المملوكية؛ مبانٍ عثمانية وأوروبية؛ سرايا، فنادق، مقاهي، قصور؛ إهمال لكنها شاهدة على التاريخ الحديث.','التل، طرابلس','معالم حديثة','ساعة','','مساءً للتجوّل'),
('al_tal_square','fr','Place Al-Tal','Fin XIXe siècle; centre de Tripoli moderne hors enceinte mamelouke; styles ottoman et européen; cafés, hôtels, palais; témoin du passé récent malgré l''abandon.','Al-Tal, Tripoli','Patrimoine moderne','1 h','','Soirée'),
('rashid_karami_international_fair','ar','معرض رشيد كرامي الدولي','فكرة من خمسينيات القرن العشرين؛ مخططات الستينيات؛ بناء 1964–1975؛ نحو مليون م²؛ تصميم أوسكار نيماير.','أرض المعرض، طرابلس','مواقع كبرى وطبيعة','1–2 ساعة','','نهارًا / فعاليات'),
('rashid_karami_international_fair','fr','Foire internationale Rachid Karami','Idée des années 1950; plans 1960; chantier 1964-1975; ~1 million m²; Oscar Niemeyer.','Tripoli','Grands sites et nature','1–2 h','','Journée / événements'),
('palm_islands_nature_reserve','ar','محمية جزيرة النخيل','ثلاث جزر غير مأهولة قبالة الميناء؛ «جزيرة الأرانب»؛ نخلتان كبيرتان؛ الجزر: الأرانب، الفنار/الرامكين، السنني.','قبالة الميناء','مواقع كبرى وطبيعة','نصف يوم (قارب)','','بحر هادئ'),
('palm_islands_nature_reserve','fr','Réserve de Palm Island','Trois îlots au large d''El-Mina; « Rabbit Island »; deux grands palmiers; Rabbit, Fanar/Ramkine, Sanani.','Au large d''El-Mina','Grands sites et nature','Demi-journée (bateau)','','Mer calme'),
('abou_ali_river','ar','نهر أبو علي','فيضان منتصف القرن العشرين وتوسيع المجرى غيّر المشهد؛ قرون من سحر نهري وثّقه الرحّالة والرسامون.','عبر طرابلس','مواقع كبرى وطبيعة','تنزّه على الضفاف','','صباحًا أو مساءً'),
('abou_ali_river','fr','Rivière Abou Ali','Inondation et élargissement au milieu du XXe siècle ont transformé le paysage; siècles de charme peint par voyageurs et artistes.','Tripoli','Grands sites et nature','Promenade sur les berges','','Matin ou soir'),
('tripolitan_cuisine','ar','المطبخ الطرابلسي','مطبخ غني؛ شهرة بالحلويات الشرقية؛ أكثر من سبعين نوعًا؛ مأكولات ومشروبات شعبية.','عبر المدينة','المطبخ والحرف','متنوّع','','الحلويات نهارًا'),
('tripolitan_cuisine','fr','Cuisine tripolitaine','Riche et variée; célèbre pour pâtisseries orientales — plus de 70 sortes — et plats de rue.','Ville entière','Cuisine et artisanat','Variable','','Journée pour pâtisseries'),
('artisanal_crafts_tripoli','ar','الحرف اليدوية','تراث حرفي عريق؛ كبار السن ينقلون المهارات؛ تحديات اندثار؛ الحرف شاهدة على هوية المدينة.','الأسواق والورش','المطبخ والحرف','1–2 ساعة','','صباح الورش'),
('artisanal_crafts_tripoli','fr','Artisanat traditionnel','Riche patrimoine artisanal; transmission aux jeunes; métiers en déclin mais témoins de l''identité tripolitaine.','Souks et ateliers','Cuisine et artisanat','1–2 h','','Matin')
) AS v(place_id, lang, name, description, location, category, duration, price, best_time)
